1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // ─────────────────────────────────────────────────────────────────
6	  // Edge cases — simplest first
7	  // ─────────────────────────────────────────────────────────────────
8	  it("empty item list → premium 5 G (only the processing fee)", () => {
9	    const result = runScenario({
10	      customer: { yearsWithMHPCO: 0 },
11	      steps: [{ op: "quote", items: [] }],
12	    });
13	    expect(result).toEqual({ results: [{ premium: 5 }] });
14	  });
15	
16	  // ─────────────────────────────────────────────────────────────────
17	  // Single-item base premiums (no modifiers, customer 0 yrs, first quote)
18	  // First insurance surcharge (+10%) applies to every item; processing fee +5
19	  // ─────────────────────────────────────────────────────────────────
20	  it.todo("single sword (no modifiers, new customer) → 100 base + 10 first ins + 5 fee = 115 G");
21	  it.todo("single amulet (no modifiers, new customer) → 60 + 6 + 5 = 71 G");
22	  it.todo("single staff (no modifiers, new customer) → 80 + 8 + 5 = 93 G");
23	  it.todo("single potion (no modifiers, new customer) → 40 + 4 + 5 = 49 G");
24	
25	  // ─────────────────────────────────────────────────────────────────
26	  // Components — block-of-3 rule
27	  // ─────────────────────────────────────────────────────────────────
28	  it.todo("2 runes → 50 G base premium (no block)");
29	  it.todo("3 runes → 60 G base premium (block applies)");
30	  it.todo("4 runes → 100 G base premium (no block — block requires exactly 3)");
31	  it.todo("7 runes → 175 G base premium (no block grouping; 7×25)");
32	
33	  // ─────────────────────────────────────────────────────────────────
34	  // "Alike" components — same type only, not same family
35	  // ─────────────────────────────────────────────────────────────────
36	  it.todo("2 runes + 1 moonstone → 75 G base premium (no block: different types)");
37	  it.todo("3 runes + 3 moonstones → 120 G base premium (two separate blocks)");
38	
39	  // ─────────────────────────────────────────────────────────────────
40	  // Item-specific modifiers (in isolation)
41	  // ─────────────────────────────────────────────────────────────────
42	  it.todo("cursed sword adds 50% risk surcharge to that item's base premium");
43	  it.todo("sword with enchantment exactly 5 → high-enchantment +30% applies");
44	  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
45	  it.todo("cursed sword with enchantment 5 → both surcharges apply");
46	
47	  // ─────────────────────────────────────────────────────────────────
48	  // Policy-wide modifiers (in isolation)
49	  // ─────────────────────────────────────────────────────────────────
50	  it.todo("customer with exactly 2 years → loyalty discount applies");
51	  it.todo("customer with 1 year → no loyalty discount");
52	  it.todo("first insurance surcharge (+10%) applies to each item in a quote");
53	  it.todo("follow-up contract discount (−15%) applies to second and later quotes");
54	
55	  // ─────────────────────────────────────────────────────────────────
56	  // Modifier scope on multi-item policies (from ❓)
57	  // ─────────────────────────────────────────────────────────────────
58	  it.todo("cursed sword + plain amulet → base 160, +50G curse (only on sword) = 210 G before fee");
59	
60	  // ─────────────────────────────────────────────────────────────────
61	  // Rounding in MHPCO's favor
62	  // ─────────────────────────────────────────────────────────────────
63	  it.todo("premium 197.5 G → 198 G (rounded up)");
64	
65	  // ─────────────────────────────────────────────────────────────────
66	  // Integration examples
67	  // ─────────────────────────────────────────────────────────────────
68	  it.todo("newcomer with cursed sword (steel, enchantment 3) → 165 G");
69	  it.todo("long-standing (3yr) customer's second contract, cursed sword enchantment 7 → 160 G");
70	
71	  // ─────────────────────────────────────────────────────────────────
72	  // Quote errors
73	  // ─────────────────────────────────────────────────────────────────
74	  it.todo("quote with unknown item type (e.g. broomstick) → throws error");
75	
76	  // ─────────────────────────────────────────────────────────────────
77	  // Claims — standard reimbursement
78	  // ─────────────────────────────────────────────────────────────────
79	  it.todo("regular sword (steel, enchantment 3), damage 500 → payout 400 (500 - 100 deductible)");
80	  it.todo("damage to a rune (insurance 250), damage 200 → payout 100 (200 - 100 deductible)");
81	
82	  // ─────────────────────────────────────────────────────────────────
83	  // Claims — special clauses
84	  // ─────────────────────────────────────────────────────────────────
85	  it.todo("dragon-material sword, enchantment 9, damage 1000 → payout 400 (50% then deductible)");
86	  it.todo("dragon-material sword, enchantment 5, damage 800 → payout 700 (full minus deductible)");
87	  it.todo("steel sword, enchantment 9, damage 1000 → payout 400 (50% then deductible)");
88	  it.todo("dragon-material sword, enchantment exactly 8, damage 1000 → payout 400 (50% then deductible)");
89	
90	  // ─────────────────────────────────────────────────────────────────
91	  // Claims — deductible per damage event
92	  // ─────────────────────────────────────────────────────────────────
93	  it.todo("dragon attack damages insured sword (500) and amulet (300) → payout 600 (deductible per item)");
94	
95	  // ─────────────────────────────────────────────────────────────────
96	  // Claims — multiple items of same type
97	  // ─────────────────────────────────────────────────────────────────
98	  it.todo("policy with two swords → insurance sum 2000, cap 4000");
99	  it.todo("two sword damages on two-sword policy → each damage has its own deductible");
100	  it.todo("damages array contains more entries of a type than insured → error (non-zero exit)");
101	
102	  // ─────────────────────────────────────────────────────────────────
103	  // Claims — cap exhaustion
104	  // ─────────────────────────────────────────────────────────────────
105	  it.todo("policy covers sword + amulet → insurance sum 1600, cap 3200");
106	  it.todo("cursed sword (insurance value 1000) → cap 2000 (premium modifiers don't raise cap)");
107	  it.todo("policy covers sword + 3 runes (block) → insurance sum 1750 (block doesn't affect sum)");
108	  it.todo("sword policy (cap 2000); 1st claim 1500 → payout 1400, remainingCap 600");
109	  it.todo("sword policy (cap 2000) after 1st claim; 2nd claim 1500 → payout 600, remainingCap 0");
110	
111	  // ─────────────────────────────────────────────────────────────────
112	  // Payout rounding
113	  // ─────────────────────────────────────────────────────────────────
114	  it.todo("payout 350.5 G → 350 G (rounded down)");
115	
116	  // ─────────────────────────────────────────────────────────────────
117	  // Claim errors
118	  // ─────────────────────────────────────────────────────────────────
119	  it.todo("claim references damage entry whose item is not part of policy → error");
120	  it.todo("claim damages an item of unknown type → error");
121	  it.todo("claim contains damage entry with amount -200 → error");
122	});
